SELECT ps.season_id, COUNT(DISTINCT ps.player_id) AS total_players
FROM player_seasons ps
GROUP BY ps.season_id;

SELECT player_id, first_name, last_name, salary, player_status 
FROM players 
WHERE player_status = 'Active' AND salary > 50000;

SELECT position_name, description 
FROM player_positions 
WHERE position_id = 0;

SELECT p.first_name, p.last_name, p.contract_expiry
FROM players p
WHERE p.contract_expiry = (SELECT MAX(contract_expiry) FROM players);
